# tools/executor.py — validate and execute tool calls from the LLM
import json
import jsonschema
from tools.registry import TOOL_REGISTRY

class ToolArgumentError(ValueError):
    """Raised when the LLM generates arguments that don't match the tool schema."""
    def __init__(self, tool_name: str, error: jsonschema.ValidationError) -> None:
        self.tool_name = tool_name
        self.schema_path = list(error.absolute_path)
        self.message = error.message
        super().__init__(
            f"[{tool_name}] Argument schema violation at {self.schema_path}: {self.message}"
        )


def execute_tool_call(tool_name: str, arguments_json: str) -> object:
    """
    Parse and validate LLM-generated tool arguments, then execute.
    arguments_json: the raw JSON string from the LLM's tool_call.function.arguments.
    """
    entry = TOOL_REGISTRY.get(tool_name)
    if entry is None:
        raise KeyError(f"Tool '{tool_name}' not found in registry")

    try:
        arguments = json.loads(arguments_json)
    except json.JSONDecodeError as e:
        raise ValueError(f"Tool '{tool_name}' arguments are not valid JSON: {e}") from e

    schema = entry["schema"]["parameters"]
    try:
        jsonschema.validate(
            instance=arguments,
            schema=schema,
            format_checker=jsonschema.FormatChecker(),
        )
    except jsonschema.ValidationError as e:
        raise ToolArgumentError(tool_name, e) from e

    return entry["fn"](**arguments)


# Agent loop integration — handle ToolArgumentError gracefully
async def run_agent_loop(messages: list[dict]) -> str:
    from openai import AsyncOpenAI
    client = AsyncOpenAI()

    response = await client.chat.completions.create(
        model="gpt-4o-2024-11-20",
        messages=messages,
        tools=TOOL_REGISTRY_DEFINITIONS,
    )
    msg = response.choices[0].message

    if msg.tool_calls:
        for tc in msg.tool_calls:
            try:
                result = execute_tool_call(tc.function.name, tc.function.arguments)
            except ToolArgumentError as e:
                # Feed the error back to the LLM so it can correct its arguments
                result = {"error": str(e), "hint": "Check the tool schema for correct field names and types."}
            messages.append({"role": "tool", "tool_call_id": tc.id, "content": json.dumps(result)})
    return msg.content or ""

import pytest
from tool_registry import TOOL_REGISTRY, schema_from_function

@pytest.mark.parametrize("tool_name,entry", TOOL_REGISTRY.items())
def test_registered_schema_matches_function(tool_name, entry):
    """Schema in registry must equal schema derived from the live function."""
    live_schema = schema_from_function(entry["fn"])
    assert entry["schema"] == live_schema, (
        f"{tool_name}: registered schema is out of sync with function signature.\n"
        f"Registered: {entry['schema']}\n"
        f"Derived:    {live_schema}"
    )

@pytest.mark.parametrize("tool_name,entry", TOOL_REGISTRY.items())
def test_schema_has_required_fields(tool_name, entry):
    schema = entry["schema"]
    assert schema.get("type") == "object", f"{tool_name}: top-level type must be 'object'"
    assert "properties" in schema, f"{tool_name}: schema must have 'properties'"
    assert schema.get("additionalProperties") is False, (
        f"{tool_name}: set additionalProperties=false to prevent prompt injection via extra keys"
    )
    for param, prop in schema["properties"].items():
        assert "description" in prop, (
            f"{tool_name}.{param}: every parameter needs a 'description' for the LLM"
        )

@pytest.mark.parametrize("tool_name,entry", TOOL_REGISTRY.items())
def test_required_list_matches_non_optional_params(tool_name, entry):
    import inspect, typing
    sig = inspect.signature(entry["fn"])
    hints = typing.get_type_hints(entry["fn"])
    non_optional = [
        name for name, param in sig.parameters.items()
        if param.default is inspect.Parameter.empty
        and name != "return"
    ]
    schema_required = set(entry["schema"].get("required", []))
    assert set(non_optional) == schema_required, (
        f"{tool_name}: 'required' list {schema_required} != non-optional params {set(non_optional)}"
    )

# scripts/lint_tool_descriptions.py
import sys
import re
from tool_registry import TOOL_REGISTRY

DESCRIPTION_MIN_WORDS = 8
VAGUE_TERMS = {"thing", "stuff", "data", "info", "object", "value"}

errors = []

for tool_name, entry in TOOL_REGISTRY.items():
    schema = entry["schema"]
    tool_desc = schema.get("description", "")
    if not tool_desc:
        errors.append(f"{tool_name}: missing top-level 'description'")
    elif len(tool_desc.split()) < DESCRIPTION_MIN_WORDS:
        errors.append(
            f"{tool_name}: description too short ({len(tool_desc.split())} words, "
            f"need {DESCRIPTION_MIN_WORDS}+): '{tool_desc}'"
        )
    for vague in VAGUE_TERMS:
        if re.search(rf'\b{vague}\b', tool_desc, re.IGNORECASE):
            errors.append(f"{tool_name}: vague term '{vague}' in description")

    for param, prop in schema.get("properties", {}).items():
        param_desc = prop.get("description", "")
        if not param_desc:
            errors.append(f"{tool_name}.{param}: missing 'description'")
        elif len(param_desc.split()) < 4:
            errors.append(
                f"{tool_name}.{param}: description too short: '{param_desc}'"
            )

if errors:
    for e in errors:
        print(f"ERROR: {e}", file=sys.stderr)
    sys.exit(1)

print(f"OK: {len(TOOL_REGISTRY)} tools passed description lint")
